const values = $input.first().json.values || [];
const dataRows = values.slice(1);

const items = [];
dataRows.forEach((row, idx) => {
  const [website_url, client_email, client_name, status] = row;
  const normalizedStatus = (status || '').trim();
  if (!website_url || !client_email) return;
  if (normalizedStatus !== '' && normalizedStatus !== 'Retry') return;
  items.push({
    json: {
      row_number: idx + 2,
      website_url,
      client_email,
      client_name: client_name || ''
    }
  });
});

return items;
